import jui from"jui";const langs={zh:{login:"登录",username:"用户名","Enter Username Please":"请输入用户名",password:"密码","Enter Password Please":"请输入密码",reset:"重置","Username Required":"用户名不能为空","Password Required":"密码不能为空","Login Success":"登录成功"}},t=e=>jui.u.t(e,langs),post=(e,s)=>jui.u.postJson(e,s),modal=new jui.modal({title:t("login"),confirmText:t("login"),cancelText:t("reset"),escClose:!0,fields:[{label:t("username"),type:"text",name:"username",id:"username",placeholder:t("Enter Username Please"),required:!0},{label:t("password"),type:"password",name:"password",id:"password",placeholder:t("Enter Password Please"),required:!0}],onSubmit:e=>{e.username.trim()?(e.password.trim()||jui.toast.error(t("Password Required")),post("/wp-json/api/v1/auth/login",{username:e.username,password:e.password}).then(e=>{200===e.code?(jui.toast.success(t("Login Success")),setTimeout(()=>{window.location.href="/"},1e3)):jui.toast.error(e.message)})):jui.toast.error(t("Username Required"))}});for(const e of document.querySelectorAll("[data-login-element]"))e.addEventListener("click",e=>{e.preventDefault(),modal.show()});